DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "parserCheckboxList.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Numeric");
Context()->variables->are(x=>'Real',y=>'Real',z=>'Real',r=>'Real',q=>'Real',p=>'Real',V=>'Real',);
Context()->noreduce('(-x)-y');
@allvars=('x','y','z','r','q','p','V');
@var=(
    list_random(@allvars),
    (@allvars)[NchooseK(7,2)],
    list_random(@allvars),
    list_random(@allvars),
    list_random(@allvars),
    'r',
);
@left=(
    Formula(non_zero_random(-9, 9) . " $var[0] + " . non_zero_random(-19, 19))->reduce,
    Formula(random(1, 9) . " $var[1] + " . random(1, 9) . " $var[2]^2")->reduce,
    Formula(random(1, 9) . ' + ' . non_zero_random(-9, 9) . "$var[3]^2")->reduce,
    Formula(random(0.1, 9, 0.1) . $var[4])->reduce,
    Formula("sqrt(" . non_zero_random(-9, 9, 0.1) . "$var[5] + " . non_zero_random(-9, 9) . ")")->reduce,
    Formula("2 pi r")->reduce
);
@right=(
    Compute(random(-9, 9)),
    Compute(random(2, 29)),
    Compute(random(-29, 29)),
    Compute(random(-9, 9, 0.1)),
    Compute(random(0, 9)),
    Formula(random(1, 20).'pi')->reduce
);
@symbol = map{(random(0, 1)) ? '=' : list_random('\lt', '\gt', '\leq', '\geq', '\neq')} (0..5);
@type = map{($_ eq '=') ? 'equation' : 'inequality'} (@symbol);
@eq = map{$BM . $left[$_]->TeX . $symbol[$_] . $right[$_]->TeX . $EM} (0..5);
$options = CheckboxList([~~@eq, "None of the above"], [0,3,5]);

############################################################
# Body
############################################################

BEGIN_PGML
Select the equations/inequalities that are linear with one variable.

[_]{$options}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
